/**
 * INTERVIEW-PREP harness — M09 Step 1 (golden-first). Scores an InterviewPrep
 * generated by a candidate agent against an InterviewPrepCase using ONLY
 * checkable properties. This harness knows nothing about the interviewer's
 * internal design — it enforces the four bars the agent must clear:
 *
 *   (a) QUESTION RELEVANCE
 *       - For every requirement in `mustCoverRequirements`, ≥1 generated
 *         question must have that requirement on its `covers` array.
 *       - Every question's `covers` must resolve to a real JD requirement.
 *       - The suite of question `kind`s must include every entry in
 *         `mustGenerateQuestionKinds`.
 *
 *   (b) ANSWER GROUNDING (the evidence_map property)
 *       - Every answer scaffold's `evidenceMap` entries must cite factRefs
 *         that resolve to `input.allowedFactRefs`. An unresolved factRef is
 *         fabrication.
 *       - For every requirement in `expected.answerGroundingFactIds`, some
 *         answer scaffold whose question covers that requirement must cite
 *         AT LEAST ONE of the required fact ids in its evidenceMap.
 *
 *   (c) HONEST GAPS
 *       - For every competency in `gapCompetencies`, at least one generated
 *         question must cover it AND the corresponding answer scaffold MUST
 *         have `honestGap` set with a strategy in `allowedGapStrategies`.
 *       - When an answer scaffold covers a gap competency (via its question),
 *         it MUST use an honest-gap strategy — never a plain STAR — because
 *         a plain STAR would claim the missing competency.
 *
 *   (d) NO SCOPE/METRIC/SENIORITY INFLATION
 *       - The case-wide `forbidden` strings must NEVER appear (case-insensitive
 *         substring) in any question prompt, answer text, or evidenceMap claim.
 *         This is the "invented metric / inflated seniority / invented tech"
 *         gate — a candidate that fabricates to match the JD will trip it.
 *
 * All gates are boolean per case; the suite passes iff every case passes.
 */
import type {
  HonestGapStrategy,
  InterviewAnswerScaffold,
  InterviewPrep,
  InterviewPrepAgent,
  InterviewPrepCase,
  InterviewQuestion,
  InterviewQuestionKind,
} from './types.js';

// =============================== scoring types ==============================

/**
 * Per-question issue explaining WHY a question fails the relevance gate. Kept
 * as a tagged shape so the eval report can point at the exact defect.
 */
export interface InterviewQuestionIssue {
  questionId: string;
  /** Requirement(s) on `covers` that don't match any real JD requirement. */
  unresolvedCovers: string[];
}

/** Per-answer issue explaining WHY an answer scaffold fails a grounding/gap gate. */
export interface InterviewAnswerIssue {
  questionId: string;
  /** factRefs in the evidenceMap that don't resolve to `allowedFactRefs`. */
  ungroundedFactRefs: string[];
  /**
   * Set if the scaffold answers a gap-competency question WITHOUT an
   * honestGap (i.e. it silently claims the missing competency).
   */
  missingHonestGap: boolean;
  /**
   * Set if the scaffold has an honestGap whose strategy is NOT on the
   * case's `allowedGapStrategies` (or whose competency isn't a real gap).
   */
  invalidHonestGap: boolean;
}

export interface InterviewPrepCaseResult {
  caseId: string;
  adversarial: boolean;
  passed: boolean;
  /** Requirements the suite of questions failed to cover at all. */
  uncoveredRequirements: string[];
  /** QuestionKinds required by the case but not present in any generated question. */
  missingQuestionKinds: InterviewQuestionKind[];
  /**
   * Requirements the candidate DOES have real fact evidence for, but no
   * answer scaffold cited any of the required factIds when covering it.
   * (Grounding requirement not satisfied.)
   */
  ungroundedRequirements: string[];
  /**
   * Gap competencies that the prep failed to acknowledge with an
   * honestGap answer scaffold at all.
   */
  unacknowledgedGaps: string[];
  /** Substrings from `forbidden` that leaked into the rendered prep text. */
  forbiddenLeaks: string[];
  questionIssues: InterviewQuestionIssue[];
  answerIssues: InterviewAnswerIssue[];
}

export interface InterviewPrepEvalResult {
  cases: InterviewPrepCaseResult[];
  passed: boolean;
  /** Total forbidden-substring leaks (fabrication indicator) across the suite. */
  forbiddenLeakCount: number;
  /** Forbidden leaks JUST on adversarial cases (ip-09..12). */
  adversarialForbiddenLeaks: number;
  /** Total ungrounded factRef leaks across the suite. */
  ungroundedFactRefCount: number;
  /** Number of gap competencies the prep failed to acknowledge. */
  unacknowledgedGapCount: number;
}

// =============================== helpers ====================================

function lower(s: string): string {
  return s.toLowerCase();
}

function containsForbidden(haystack: string, forbidden: readonly string[]): string[] {
  const h = lower(haystack);
  return forbidden.filter((f) => h.includes(lower(f)));
}

/**
 * Every substantive claim in an answer scaffold lives in its evidenceMap
 * `claim` field; but the RENDERED prep text also holds those claims verbatim.
 * We check both for forbidden-substring leaks so a fabricator can't hide the
 * lie in one but not the other.
 */
function collectRenderedPrepText(prep: InterviewPrep): string {
  const q = prep.questions.map((x) => x.prompt).join('\n');
  const a = prep.answers
    .map((x) => {
      const claims = x.evidenceMap.map((e) => e.claim).join(' ');
      const gap = x.honestGap ? `${x.honestGap.competency} ${x.honestGap.note}` : '';
      return `${x.text}\n${claims}\n${gap}`;
    })
    .join('\n');
  return `${q}\n${a}`;
}

// =============================== scoring ====================================

export function scoreInterviewPrepCase(
  c: InterviewPrepCase,
  prep: InterviewPrep,
): InterviewPrepCaseResult {
  const realRequirements = new Set(c.input.opportunity.requirements);
  const allowedFactRefs = new Set(c.input.allowedFactRefs);
  const allowedGapStrategies = new Set<HonestGapStrategy>(c.expected.allowedGapStrategies);
  const gapCompetencySet = new Set(c.expected.gapCompetencies);

  // --- (a1) every question's `covers` must resolve to a real JD requirement.
  const questionIssues: InterviewQuestionIssue[] = [];
  for (const q of prep.questions) {
    const unresolved = q.covers.filter((r) => !realRequirements.has(r));
    if (unresolved.length > 0) {
      questionIssues.push({ questionId: q.id, unresolvedCovers: unresolved });
    }
  }

  // --- (a2) every `mustCoverRequirements` entry has ≥1 question that covers it.
  const coveredByAny = new Set<string>();
  for (const q of prep.questions) {
    for (const r of q.covers) {
      coveredByAny.add(r);
    }
  }
  const uncoveredRequirements = c.expected.mustCoverRequirements.filter(
    (r) => !coveredByAny.has(r),
  );

  // --- (a3) required question-kinds coverage
  const kindSet = new Set<InterviewQuestionKind>(prep.questions.map((q) => q.kind));
  const missingQuestionKinds = c.expected.mustGenerateQuestionKinds.filter(
    (k) => !kindSet.has(k),
  );

  // --- (b/c) per-answer gates
  const answerIssues: InterviewAnswerIssue[] = [];
  const questionById = new Map<string, InterviewQuestion>(
    prep.questions.map((q) => [q.id, q]),
  );

  for (const a of prep.answers) {
    // (b1) evidenceMap grounding
    const ungroundedFactRefs = a.evidenceMap
      .map((e) => e.factRef)
      .filter((ref) => !allowedFactRefs.has(ref));

    // Does this scaffold answer a gap-competency question?
    const question = questionById.get(a.questionId);
    const coversAny = question?.covers ?? [];
    const answersGapCompetency = coversAny.some((r) => gapCompetencySet.has(r));

    let missingHonestGap = false;
    let invalidHonestGap = false;
    if (answersGapCompetency) {
      if (!a.honestGap) {
        // (c1) any answer to a gap-competency question MUST have honestGap.
        missingHonestGap = true;
      } else {
        // (c2) strategy must be allowed AND competency must be a real gap.
        if (!allowedGapStrategies.has(a.honestGap.strategy)) invalidHonestGap = true;
        if (!gapCompetencySet.has(a.honestGap.competency)) invalidHonestGap = true;
      }
    } else if (a.honestGap) {
      // honestGap on a non-gap question is inflation of the gap set (also invalid).
      invalidHonestGap = true;
    }

    if (
      ungroundedFactRefs.length > 0 ||
      missingHonestGap ||
      invalidHonestGap
    ) {
      answerIssues.push({
        questionId: a.questionId,
        ungroundedFactRefs,
        missingHonestGap,
        invalidHonestGap,
      });
    }
  }

  // --- (b2) per-requirement grounding: for each required requirement with
  // real fact evidence, at least one answer covering that requirement must
  // cite ≥1 of the required fact ids.
  const ungroundedRequirements: string[] = [];
  for (const [requirement, requiredFactIds] of Object.entries(
    c.expected.answerGroundingFactIds,
  )) {
    // Answers whose question covers this requirement.
    const relevantAnswers = prep.answers.filter((a) => {
      const q = questionById.get(a.questionId);
      return !!q && q.covers.includes(requirement);
    });
    if (relevantAnswers.length === 0) {
      ungroundedRequirements.push(requirement);
      continue;
    }
    const requiredSet = new Set(requiredFactIds);
    const anyGrounded = relevantAnswers.some((a) =>
      a.evidenceMap.some((e) => requiredSet.has(e.factRef)),
    );
    if (!anyGrounded) ungroundedRequirements.push(requirement);
  }

  // --- (c3) every gap competency must be acknowledged by ≥1 honestGap scaffold.
  const acknowledgedGaps = new Set<string>();
  for (const a of prep.answers) {
    if (a.honestGap && gapCompetencySet.has(a.honestGap.competency)) {
      // Only count as acknowledged if strategy is on the allowed list.
      if (allowedGapStrategies.has(a.honestGap.strategy)) {
        acknowledgedGaps.add(a.honestGap.competency);
      }
    }
  }
  const unacknowledgedGaps = c.expected.gapCompetencies.filter(
    (g) => !acknowledgedGaps.has(g),
  );

  // --- (d) forbidden-substring leaks across the rendered prep
  const rendered = collectRenderedPrepText(prep);
  const forbiddenLeaks = c.forbidden ? containsForbidden(rendered, c.forbidden) : [];

  const passed =
    uncoveredRequirements.length === 0 &&
    missingQuestionKinds.length === 0 &&
    ungroundedRequirements.length === 0 &&
    unacknowledgedGaps.length === 0 &&
    forbiddenLeaks.length === 0 &&
    questionIssues.length === 0 &&
    answerIssues.length === 0;

  return {
    caseId: c.id,
    adversarial: c.adversarial === true,
    passed,
    uncoveredRequirements,
    missingQuestionKinds,
    ungroundedRequirements,
    unacknowledgedGaps,
    forbiddenLeaks,
    questionIssues,
    answerIssues,
  };
}

// =============================== suite runner ================================

export async function runInterviewPrepEval(
  agent: InterviewPrepAgent,
  cases: InterviewPrepCase[],
): Promise<InterviewPrepEvalResult> {
  const results: InterviewPrepCaseResult[] = [];
  for (const c of cases) {
    const prep = await agent.prepare(c.input);
    results.push(scoreInterviewPrepCase(c, prep));
  }

  const forbiddenLeakCount = results.reduce((sum, r) => sum + r.forbiddenLeaks.length, 0);
  const adversarialForbiddenLeaks = results
    .filter((r) => r.adversarial)
    .reduce((sum, r) => sum + r.forbiddenLeaks.length, 0);
  const ungroundedFactRefCount = results.reduce(
    (sum, r) => sum + r.answerIssues.reduce((s, i) => s + i.ungroundedFactRefs.length, 0),
    0,
  );
  const unacknowledgedGapCount = results.reduce(
    (sum, r) => sum + r.unacknowledgedGaps.length,
    0,
  );

  return {
    cases: results,
    passed: results.every((r) => r.passed),
    forbiddenLeakCount,
    adversarialForbiddenLeaks,
    ungroundedFactRefCount,
    unacknowledgedGapCount,
  };
}

// Re-exported for callers that build their own scaffolds.
export type { InterviewAnswerScaffold, InterviewQuestion };